import { useState } from "react";
import { useTheme } from "@/app/provider";
import { Download, FileSpreadsheet, FileText, ChevronDown, Calendar } from "lucide-react";

export interface ExportTemplate {
  id: string;
  name: string;
  data: any;
  generator: (data: any, format: 'excel' | 'pdf') => Promise<string | Blob>;
}

interface UniversalExportButtonProps {
  template: ExportTemplate;
  filename?: string;
  disabled?: boolean;
  className?: string;
  size?: 'sm' | 'md' | 'lg';
  variant?: 'primary' | 'secondary' | 'outline';
}

function getPacificTimeDate(): Date {
  const now = new Date();
  return new Date(now.toLocaleString("en-US", {timeZone: "America/Los_Angeles"}));
}

export default function UniversalExportButton({
  template,
  filename,
  disabled = false,
  className = "",
  size = 'md',
  variant = 'primary'
}: UniversalExportButtonProps) {
  const { themeType } = useTheme();
  const isDark = themeType === "dark";

  const [isExporting, setIsExporting] = useState(false);
  const [showDropdown, setShowDropdown] = useState(false);

  const sizeClasses = {
    sm: "px-3 py-1.5 text-sm",
    md: "px-4 py-2 text-sm",
    lg: "px-6 py-3 text-base"
  };

  const getVariantClasses = () => {
    switch (variant) {
      case 'secondary':
        return "bg-[hsl(var(--secondary))] text-[hsl(var(--secondary-foreground))] hover:bg-[hsl(var(--secondary))]/80";
      case 'outline':
        return "border border-[hsl(var(--border))] bg-transparent text-[hsl(var(--foreground))] hover:bg-[hsl(var(--accent))]";
      default:
        return "bg-[hsl(var(--sidebar-primary))] text-[hsl(var(--sidebar-primary-foreground))] hover:bg-[hsl(var(--sidebar-primary))]/90";
    }
  };

  const getMonthName = (month: number) => {
    const months = [
      'January', 'February', 'March', 'April', 'May', 'June',
      'July', 'August', 'September', 'October', 'November', 'December'
    ];
    return months[month - 1] || '';
  };

  const handleExport = async (monthType: 'current' | 'last') => {
    setIsExporting(true);
    setShowDropdown(false);

    try {
      const pacificTime = getPacificTimeDate();
      let exportMonth, exportYear;

      if (monthType === 'current') {
        exportMonth = pacificTime.getMonth() + 1;
        exportYear = pacificTime.getFullYear();
      } else {
        pacificTime.setMonth(pacificTime.getMonth() - 1);
        exportMonth = pacificTime.getMonth() + 1;
        exportYear = pacificTime.getFullYear();
      }

      const exportData = {
        ...template.data,
        month: exportMonth,
        year: exportYear
      };

      console.log(`🔄 Exporting ${template.name} for ${getMonthName(exportMonth)} ${exportYear}`);
      
      const result = await template.generator(exportData, 'excel');
      
      const timestamp = new Date().toISOString().split('T')[0];
      const monthName = getMonthName(exportMonth);
      const baseFilename = filename || `${template.name}_${monthName}_${exportYear}_${timestamp}`;
      const fullFilename = `${baseFilename}.xlsx`;

      if (result instanceof Blob) {
        const url = URL.createObjectURL(result);
        const a = document.createElement('a');
        a.href = url;
        a.download = fullFilename;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
      }

      console.log(`✅ ${template.name} exported successfully`);
      
    } catch (error) {
      console.error(`❌ Error exporting ${template.name}:`, error);
      alert(`Failed to export ${template.name}. Please try again.`);
    } finally {
      setIsExporting(false);
    }
  };

  const pacificTime = getPacificTimeDate();
  const currentMonth = getMonthName(pacificTime.getMonth() + 1);
  const lastMonthDate = new Date(pacificTime);
  lastMonthDate.setMonth(lastMonthDate.getMonth() - 1);
  const lastMonth = getMonthName(lastMonthDate.getMonth() + 1);

  return (
    <div className="relative inline-block">
      <button
        onClick={() => setShowDropdown(!showDropdown)}
        disabled={disabled || isExporting}
        className={`
          ${sizeClasses[size]}
          ${getVariantClasses()}
          rounded transition-colors font-medium flex items-center
          ${disabled || isExporting ? "opacity-50 cursor-not-allowed" : "cursor-pointer"}
          ${className}
        `}
      >
        <Download size={16} className="mr-2" />
        {isExporting ? `Exporting...` : `Export`}
        <ChevronDown size={14} className="ml-2" />
      </button>

      {showDropdown && !disabled && !isExporting && (
        <div
          className={`absolute top-full right-0 mt-1 w-48 rounded-md shadow-lg z-50 ${
            isDark
              ? "bg-[hsl(var(--card))] border border-[hsl(var(--border))]"
              : "bg-white border border-[hsl(var(--border))]"
          }`}
        >
          <div className="py-1">
            <button
              onClick={() => handleExport('current')}
              className={`w-full px-4 py-3 text-left text-sm flex items-center hover:bg-[hsl(var(--accent))] transition-colors ${
                isDark ? "text-[hsl(var(--foreground))]" : "text-gray-700"
              }`}
            >
              <FileSpreadsheet size={16} className="mr-3 text-green-600" />
              <div>
                <div className="font-medium">{currentMonth} {pacificTime.getFullYear()}</div>
                <div className="text-xs text-[hsl(var(--muted-foreground))]">Current Month</div>
              </div>
            </button>
            
            <button
              onClick={() => handleExport('last')}
              className={`w-full px-4 py-3 text-left text-sm flex items-center hover:bg-[hsl(var(--accent))] transition-colors ${
                isDark ? "text-[hsl(var(--foreground))]" : "text-gray-700"
              }`}
            >
              <FileSpreadsheet size={16} className="mr-3 text-green-600" />
              <div>
                <div className="font-medium">{lastMonth} {lastMonthDate.getFullYear()}</div>
                <div className="text-xs text-[hsl(var(--muted-foreground))]">Last Month</div>
              </div>
            </button>
          </div>
        </div>
      )}

      {showDropdown && (
        <div
          className="fixed inset-0 z-40"
          onClick={() => setShowDropdown(false)}
        />
      )}
    </div>
  );
}

// lib/adminGuard.ts
/**
 * Admin Route Protection
 * Hard locks admin routes - only admins can access
 */

import { createClient } from "@/utils/supabase/server";
import { redirect } from "next/navigation";
import { authLogger } from "./authLogger";

export async function requireAdmin() {
  const supabase = await createClient();
  
  // Get current session
  const { data: { session }, error: sessionError } = await supabase.auth.getSession();
  
  if (sessionError || !session) {
    authLogger.securityEvent('Admin access attempt without session');
    redirect('/sign-in?error=auth_required&message=Please sign in to continue');
  }

  // Get user profile to check role
  const { data: profile, error: profileError } = await supabase
    .from('profiles')
    .select('role, display_name')
    .eq('id', session.user.id)
    .single();

  if (profileError || !profile) {
    authLogger.authError('Failed to fetch user profile', { 
      userId: session.user.id,
      error: profileError?.message 
    });
    redirect('/sign-in?error=profile_error&message=Could not verify permissions');
  }

  // Check if user is admin
  if (profile.role !== 'admin') {
    authLogger.adminAccessDenied(
      session.user.id,
      session.user.email || '',
      'admin dashboard'
    );
    
    redirect('/?error=access_denied&message=You do not have permission to access this area');
  }

  // Access granted
  authLogger.adminSignIn(session.user.id, session.user.email || '');
  
  return {
    user: session.user,
    profile
  };
}

// Client-side admin check hook
export function useAdminGuard() {
  // This should be used in client components
  // Returns whether user is admin
  return {
    isAdmin: false, // Will be hydrated from server
    isLoading: true
  };
}

// lib/escpos.ts
// ESC/POS command builder for thermal receipt printers.
// Compatible with: Epson, Star, Bixolon, HPRT, most 58mm/80mm USB & BT printers.

const ESC = 0x1b;
const GS  = 0x1d;

export class EscPos {
  private buf: number[] = [];

  // ── Init ──────────────────────────────────────────────────────
  init(): this {
    this.buf.push(ESC, 0x40);          // ESC @ — full reset
    return this;
  }

  // ── Text ──────────────────────────────────────────────────────
  text(s: string): this {
    for (let i = 0; i < s.length; i++) {
      const code = s.charCodeAt(i);
      this.buf.push(code < 256 ? code : 0x3f); // '?' for non-latin
    }
    return this;
  }

  lf(n = 1): this {
    for (let i = 0; i < n; i++) this.buf.push(0x0a);
    return this;
  }

  // ── Alignment ─────────────────────────────────────────────────
  center(): this  { this.buf.push(ESC, 0x61, 0x01); return this; }
  left(): this    { this.buf.push(ESC, 0x61, 0x00); return this; }
  right(): this   { this.buf.push(ESC, 0x61, 0x02); return this; }

  // ── Style ─────────────────────────────────────────────────────
  bold(on: boolean): this {
    this.buf.push(ESC, 0x45, on ? 0x01 : 0x00);
    return this;
  }

  doubleHeight(on: boolean): this {
    this.buf.push(GS, 0x21, on ? 0x01 : 0x00);
    return this;
  }

  // ── Helpers ───────────────────────────────────────────────────
  /** Two-column row: left text and right text, padded to `width` chars. */
  row(left: string, right: string, width = 32): this {
    const pad = width - left.length - right.length;
    const spaces = pad > 0 ? " ".repeat(pad) : " ";
    return this.text(left + spaces + right).lf();
  }

  /** Dashed divider line */
  divider(width = 32): this {
    return this.text("-".repeat(width)).lf();
  }

  // ── Feed & cut ────────────────────────────────────────────────
  feed(lines = 4): this {
    this.buf.push(ESC, 0x64, lines);   // ESC d — feed n lines
    return this;
  }

  /** Full cut (GS V 0x41 0) — most modern printers */
  cut(): this {
    this.buf.push(GS, 0x56, 0x41, 0x00);
    return this;
  }

  // ── Output ────────────────────────────────────────────────────
  bytes(): Uint8Array {
    return new Uint8Array(this.buf);
  }
}

// ── Format helpers ───────────────────────────────────────────────────────────

export function fmtMoney(cents: number): string {
  return `$${(cents / 100).toFixed(2)}`;
}

export function fmtDate(date = new Date()): string {
  return date.toLocaleDateString("en-US", {
    month: "short", day: "numeric", year: "numeric",
    hour: "numeric", minute: "2-digit",
  });
}

// lib/thermalPrinter.ts
// Handles connection + printing to thermal printers via:
//   - Web Serial API  (USB cable — Chrome/Edge desktop)
//   - Web Bluetooth   (Bluetooth — Chrome desktop, NOT iOS Safari)
//
// iOS note: Neither Web Serial nor Web Bluetooth are available on Safari iOS.
// For iOS printing use window.print() with the @media print stylesheet instead.

import { EscPos, fmtMoney, fmtDate } from "./escpos";
import type { POSCartItem } from "@/components/POS/types";

// ── Type declarations (not in lib.dom.d.ts yet) ─────────────────────────────
declare global {
  interface Navigator {
    serial?: {
      requestPort(opts?: any): Promise<SerialPort>;
      getPorts(): Promise<SerialPort[]>;
    };
    bluetooth?: {
      requestDevice(opts: any): Promise<BluetoothDevice>;
    };
  }
  interface SerialPort {
    open(opts: any): Promise<void>;
    close(): Promise<void>;
    writable: WritableStream<Uint8Array>;
    readable: ReadableStream<Uint8Array>;
  }
  interface BluetoothDevice {
    gatt?: BluetoothRemoteGATTServer;
    name?: string;
  }
  interface BluetoothRemoteGATTServer {
    connect(): Promise<BluetoothRemoteGATTServer>;
    disconnect(): void;
    connected: boolean;
    getPrimaryService(uuid: string): Promise<BluetoothRemoteGATTService>;
  }
  interface BluetoothRemoteGATTService {
    getCharacteristic(uuid: string): Promise<BluetoothRemoteGATTCharacteristic>;
  }
  interface BluetoothRemoteGATTCharacteristic {
    writeValueWithoutResponse(data: BufferSource): Promise<void>;
    writeValue(data: BufferSource): Promise<void>;
  }
}

// Standard BT printer service/characteristic UUIDs (covers most brands)
const SERIAL_SERVICE_UUID  = "000018f0-0000-1000-8000-00805f9b34fb";
const SERIAL_CHAR_UUID     = "00002af1-0000-1000-8000-00805f9b34fb";

export type PrinterConnectionType = "usb" | "bluetooth" | "none";

export interface PrinterConnection {
  type: PrinterConnectionType;
  name: string;
  // USB
  port?: SerialPort;
  writer?: WritableStreamDefaultWriter<Uint8Array>;
  // Bluetooth
  device?: BluetoothDevice;
  characteristic?: BluetoothRemoteGATTCharacteristic;
}

// ── Capabilities check ───────────────────────────────────────────────────────

export function canUseSerial(): boolean {
  return typeof navigator !== "undefined" && !!navigator.serial;
}

export function canUseBluetooth(): boolean {
  return typeof navigator !== "undefined" && !!navigator.bluetooth;
}

// ── Connect via USB / Web Serial ─────────────────────────────────────────────

export async function connectUSB(): Promise<PrinterConnection> {
  if (!navigator.serial) throw new Error("Web Serial not supported in this browser.");
  const port = await navigator.serial.requestPort({
    filters: [], // show all serial devices
  });
  await port.open({ baudRate: 9600 });
  const writer = port.writable.getWriter();
  return { type: "usb", name: "USB Printer", port, writer };
}

export async function disconnectUSB(conn: PrinterConnection): Promise<void> {
  try { conn.writer?.releaseLock(); } catch {}
  try { await conn.port?.close(); } catch {}
}

// ── Connect via Bluetooth ────────────────────────────────────────────────────

export async function connectBluetooth(): Promise<PrinterConnection> {
  if (!navigator.bluetooth) throw new Error("Web Bluetooth not supported in this browser.");

  const device = await navigator.bluetooth.requestDevice({
    acceptAllDevices: true,
    optionalServices: [SERIAL_SERVICE_UUID, "battery_service"],
  });

  const server = await device.gatt!.connect();
  let characteristic: BluetoothRemoteGATTCharacteristic;

  try {
    const service = await server.getPrimaryService(SERIAL_SERVICE_UUID);
    characteristic = await service.getCharacteristic(SERIAL_CHAR_UUID);
  } catch {
    throw new Error(
      "Connected but couldn't find printer service. Make sure the printer is in pairing mode and supports BT serial."
    );
  }

  return {
    type: "bluetooth",
    name: device.name ?? "Bluetooth Printer",
    device,
    characteristic,
  };
}

export function disconnectBluetooth(conn: PrinterConnection): void {
  if (conn.device?.gatt?.connected) {
    conn.device.gatt.disconnect();
  }
}

// ── Send bytes to printer ────────────────────────────────────────────────────

async function sendBytes(conn: PrinterConnection, data: Uint8Array): Promise<void> {
  if (conn.type === "usb" && conn.writer) {
    await conn.writer.write(data);

  } else if (conn.type === "bluetooth" && conn.characteristic) {
    // BT has a 512-byte MTU limit — chunk the data
    const CHUNK = 512;
    for (let i = 0; i < data.length; i += CHUNK) {
      const chunk = data.slice(i, i + CHUNK);
      try {
        await conn.characteristic.writeValueWithoutResponse(chunk);
      } catch {
        await conn.characteristic.writeValue(chunk); // fallback
      }
      // Small delay between chunks to avoid buffer overflow
      await new Promise((r) => setTimeout(r, 20));
    }
  } else {
    throw new Error("No active printer connection.");
  }
}

// ── Build receipt bytes ──────────────────────────────────────────────────────

export interface ReceiptData {
  orderNumber: string;
  items: POSCartItem[];
  subtotalCents: number;
  discountCents?: number;
  totalCents: number;
  customerName?: string | null;
  customerEmail?: string | null;
  discountLabel?: string | null;
  date?: Date;
}

export function buildReceiptBytes(data: ReceiptData, width = 32): Uint8Array {
  const p = new EscPos();
  const {
    orderNumber, items, subtotalCents, discountCents = 0,
    totalCents, customerName, customerEmail, discountLabel, date,
  } = data;

  p.init()
   // ── Header ──────────────────────────────────────────────────
   .center()
   .bold(true).doubleHeight(true)
   .text("Desert Cowgirl Co.").lf()
   .doubleHeight(false).bold(false)
   .lf()
   .text(fmtDate(date)).lf()
   .text(orderNumber).lf()
   .lf()
   .divider(width)
   .left()
   // ── Items ────────────────────────────────────────────────────
   .lf();

  for (const item of items) {
    const label = item.variant_title && item.variant_title !== "Default" && item.variant_title !== ""
      ? `${item.product_title} / ${item.variant_title}`
      : item.product_title;
    // Truncate name to fit
    const name = label.length > width - 8 ? label.slice(0, width - 9) + "…" : label;
    p.row(`${item.quantity}x ${name}`, fmtMoney(item.price_cents * item.quantity), width);
  }

  p.lf()
   .divider(width)
   .lf();

  // ── Totals ───────────────────────────────────────────────────
  if (discountCents > 0) {
    p.row("Subtotal", fmtMoney(subtotalCents), width)
     .row(discountLabel ? `Discount (${discountLabel})` : "Discount", `-${fmtMoney(discountCents)}`, width);
  }

  p.bold(true)
   .row("TOTAL", fmtMoney(totalCents), width)
   .bold(false)
   .lf()
   .row("Payment", "Paid", width)
   .lf()
   .divider(width)
   // ── Footer ───────────────────────────────────────────────────
   .lf()
   .center();

  if (customerName) p.text(customerName).lf();
  if (customerEmail) p.text(customerEmail).lf();

  p.lf()
   .text("Thank you for shopping with us!").lf()
   .text("desertcowgirlco.com").lf()
   .feed(4)
   .cut();

  return p.bytes();
}

// ── Main print function ──────────────────────────────────────────────────────

export async function printReceipt(
  conn: PrinterConnection,
  data: ReceiptData,
  paperWidth: 58 | 80 = 58
): Promise<void> {
  // 58mm ≈ 32 chars, 80mm ≈ 48 chars at default font
  const charWidth = paperWidth === 80 ? 48 : 32;
  const bytes = buildReceiptBytes(data, charWidth);
  await sendBytes(conn, bytes);
}

// lib/robustPDFGenerator.ts

export interface BusinessCleaningRecord {
  business_id: number;
  business_name: string;
  address: string;
  cleaned_dates: number[];
}

export class RobustPDFGenerator {
  static async generateBillingPDF(businesses: BusinessCleaningRecord[], month: number, year: number): Promise<Blob> {
    try {
      // Dynamic import to avoid SSR issues
      const { jsPDF } = await import('jspdf');
      
      // Create PDF with proper settings
      const pdf = new jsPDF({
        orientation: 'landscape',
        unit: 'mm',
        format: 'a4',
        putOnlyUsedFonts: true,
        compress: true
      });

      const pageWidth = pdf.internal.pageSize.getWidth();
      const pageHeight = pdf.internal.pageSize.getHeight();
      const margin = 10;
      const daysInMonth = new Date(year, month, 0).getDate();
      
      const monthNames = [
        'January', 'February', 'March', 'April', 'May', 'June',
        'July', 'August', 'September', 'October', 'November', 'December'
      ];
      const monthName = monthNames[month - 1];

      // Calculate table dimensions
      const businessNameWidth = 60;
      const availableWidth = pageWidth - margin * 2 - businessNameWidth;
      const dayWidth = Math.max(availableWidth / daysInMonth, 4); // Minimum 4mm per day
      const rowHeight = 8;
      const headerHeight = 12;

      // Header section
      pdf.setFont('helvetica', 'bold');
      pdf.setFontSize(18);
      pdf.text('DART COMMERCIAL SERVICES', pageWidth / 2, 20, { align: 'center' });
      
      pdf.setFontSize(14);
      pdf.text('MONTHLY BILLING REPORT', pageWidth / 2, 30, { align: 'center' });
      
      pdf.setFontSize(12);
      pdf.text(`${monthName.toUpperCase()} ${year}`, pageWidth / 2, 40, { align: 'center' });

      // Table start position
      let currentY = 50;
      const tableStartY = currentY;

      // Function to draw table headers
      const drawHeaders = (y: number) => {
        pdf.setFont('helvetica', 'bold');
        pdf.setFontSize(10);
        
        // Business name header
        pdf.setDrawColor(0, 0, 0);
        pdf.setLineWidth(0.5);
        pdf.rect(margin, y, businessNameWidth, headerHeight);
        pdf.text('BUSINESS NAME', margin + 2, y + 8);
        
        // Day headers
        pdf.setFontSize(8);
        for (let day = 1; day <= daysInMonth; day++) {
          const x = margin + businessNameWidth + (day - 1) * dayWidth;
          pdf.rect(x, y, dayWidth, headerHeight);
          
          // Center the day number
          const textWidth = pdf.getTextWidth(day.toString());
          const textX = x + (dayWidth - textWidth) / 2;
          pdf.text(day.toString(), textX, y + 8);
        }
        
        return y + headerHeight;
      };

      // Draw initial headers
      currentY = drawHeaders(currentY);

      // Business rows
      pdf.setFont('helvetica', 'normal');
      pdf.setFontSize(8);
      
      businesses.forEach((business, index) => {
        // Check if we need a new page
        if (currentY + rowHeight > pageHeight - margin - 20) {
          pdf.addPage();
          currentY = margin + 10;
          // Redraw headers on new page
          currentY = drawHeaders(currentY);
        }

        // Business name cell
        pdf.setDrawColor(0, 0, 0);
        pdf.setLineWidth(0.3);
        pdf.rect(margin, currentY, businessNameWidth, rowHeight);
        
        // Truncate business name if too long
        let businessName = business.business_name;
        const maxWidth = businessNameWidth - 4;
        while (pdf.getTextWidth(businessName) > maxWidth && businessName.length > 3) {
          businessName = businessName.substring(0, businessName.length - 4) + '...';
        }
        
        pdf.text(businessName, margin + 2, currentY + 5);

        // Day cells
        for (let day = 1; day <= daysInMonth; day++) {
          const x = margin + businessNameWidth + (day - 1) * dayWidth;
          pdf.rect(x, currentY, dayWidth, rowHeight);
          
          if (business.cleaned_dates.includes(day)) {
            pdf.setFont('helvetica', 'bold');
            pdf.setFontSize(12);
            
            // Center the checkmark
            const checkmark = '✓';
            const textWidth = pdf.getTextWidth(checkmark);
            const textX = x + (dayWidth - textWidth) / 2;
            pdf.text(checkmark, textX, currentY + 6);
            
            pdf.setFont('helvetica', 'normal');
            pdf.setFontSize(8);
          }
        }

        currentY += rowHeight;
      });

      // Footer section
      currentY += 15;
      if (currentY + 30 > pageHeight - margin) {
        pdf.addPage();
        currentY = margin + 20;
      }

      // Signature section
      pdf.setFont('helvetica', 'bold');
      pdf.setFontSize(12);
      
      const signatureY = currentY;
      pdf.text('JOB COACH SIGNATURE:', margin, signatureY);
      pdf.setLineWidth(0.5);
      pdf.line(margin + 55, signatureY + 2, margin + 120, signatureY + 2);
      
      pdf.text('DATE:', pageWidth - margin - 50, signatureY);
      pdf.line(pageWidth - margin - 35, signatureY + 2, pageWidth - margin - 5, signatureY + 2);

      // Add metadata
      pdf.setProperties({
        title: `CMS Billing Report - ${monthName} ${year}`,
        subject: 'Monthly Billing Report',
        author: 'DART Commercial Services',
        creator: 'CMS Application',
        producer: 'jsPDF'
      });

      // Generate blob with proper MIME type
      const pdfOutput = pdf.output('blob', { type: 'application/pdf' });
      
      // Validate the blob
      if (!pdfOutput || pdfOutput.size === 0) {
        throw new Error('Generated PDF is empty');
      }

      console.log(`✅ PDF generated successfully: ${pdfOutput.size} bytes`);
      return pdfOutput;

    } catch (error) {
      console.error('❌ Error generating PDF:', error);
      throw new Error(`PDF generation failed: ${error instanceof Error ? error.message : 'Unknown error'}`);
    }
  }

  // Alternative: Generate using HTML-to-PDF approach with proper canvas handling
  static async generateBillingPDFFromHTML(businesses: BusinessCleaningRecord[], month: number, year: number): Promise<Blob> {
    try {
      // Dynamic imports
      const { jsPDF } = await import('jspdf');
      const html2canvas = await import('html2canvas');
      
      const monthNames = [
        'January', 'February', 'March', 'April', 'May', 'June',
        'July', 'August', 'September', 'October', 'November', 'December'
      ];
      const monthName = monthNames[month - 1];
      const daysInMonth = new Date(year, month, 0).getDate();

      // Create optimized HTML for PDF conversion
      const htmlContent = `
        <div style="width: 1123px; height: 794px; padding: 20px; font-family: Arial, sans-serif; background: white; box-sizing: border-box;">
          <div style="text-align: center; margin-bottom: 30px;">
            <h1 style="margin: 0; font-size: 24px; font-weight: bold;">DART COMMERCIAL SERVICES</h1>
            <h2 style="margin: 10px 0; font-size: 18px;">MONTHLY BILLING REPORT</h2>
            <h3 style="margin: 10px 0; font-size: 16px; text-transform: uppercase;">${monthName} ${year}</h3>
          </div>
          
          <table style="border-collapse: collapse; width: 100%; font-size: 10px;">
            <thead>
              <tr>
                <th style="border: 1px solid black; padding: 4px; background: #f0f0f0; width: 150px; text-align: left;">BUSINESS NAME</th>
                ${Array.from({length: daysInMonth}, (_, i) => 
                  `<th style="border: 1px solid black; padding: 4px; background: #f0f0f0; width: 20px; text-align: center;">${i + 1}</th>`
                ).join('')}
              </tr>
            </thead>
            <tbody>
              ${businesses.map(business => `
                <tr>
                  <td style="border: 1px solid black; padding: 4px; text-align: left; font-weight: bold;">
                    ${business.business_name.length > 25 ? business.business_name.substring(0, 22) + '...' : business.business_name}
                  </td>
                  ${Array.from({length: daysInMonth}, (_, i) => {
                    const day = i + 1;
                    const isCleaned = business.cleaned_dates.includes(day);
                    return `<td style="border: 1px solid black; padding: 4px; text-align: center; font-weight: bold; font-size: 14px;">
                      ${isCleaned ? '✓' : ''}
                    </td>`;
                  }).join('')}
                </tr>
              `).join('')}
            </tbody>
          </table>
          
          <div style="margin-top: 40px; display: flex; justify-content: space-between; align-items: center;">
            <div style="font-weight: bold; font-size: 14px;">
              JOB COACH SIGNATURE: <span style="display: inline-block; width: 200px; border-bottom: 2px solid black; margin-left: 10px;"></span>
            </div>
            <div style="font-weight: bold; font-size: 14px;">
              DATE: <span style="display: inline-block; width: 150px; border-bottom: 2px solid black; margin-left: 10px;"></span>
            </div>
          </div>
        </div>
      `;

      // Create temporary container
      const container = document.createElement('div');
      container.innerHTML = htmlContent;
      container.style.position = 'absolute';
      container.style.left = '-9999px';
      container.style.top = '-9999px';
      document.body.appendChild(container);

      try {
        // Generate canvas
        const canvas = await html2canvas.default(container.firstElementChild as HTMLElement, {
          scale: 2,
          useCORS: true,
          allowTaint: false,
          backgroundColor: '#ffffff',
          width: 1123,
          height: 794,
          logging: false
        });

        // Create PDF
        const pdf = new jsPDF({
          orientation: 'landscape',
          unit: 'px',
          format: [1123, 794]
        });

        const imgData = canvas.toDataURL('image/png', 1.0);
        pdf.addImage(imgData, 'PNG', 0, 0, 1123, 794);

        // Add metadata
        pdf.setProperties({
          title: `CMS Billing Report - ${monthName} ${year}`,
          subject: 'Monthly Billing Report',
          author: 'DART Commercial Services'
        });

        const pdfBlob = pdf.output('blob');
        return pdfBlob;

      } finally {
        // Clean up
        document.body.removeChild(container);
      }

    } catch (error) {
      console.error('❌ Error generating PDF from HTML:', error);
      throw new Error(`HTML-to-PDF generation failed: ${error instanceof Error ? error.message : 'Unknown error'}`);
    }
  }
}
